import{_ as e,o as l,c as a,a2 as r}from"./chunks/framework.BQ1gajhD.js";const x=JSON.parse('{"title":"北京话剧地图","description":"","frontmatter":{},"headers":[],"relativePath":"guide/theater.md","filePath":"guide/theater.md","lastUpdated":1784773307000}'),n={name:"guide/theater.md"};function d(s,t,i,g,o,h){return l(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="北京话剧地图" tabindex="-1">北京话剧地图 <a class="header-anchor" href="#北京话剧地图" aria-label="Permalink to &quot;北京话剧地图&quot;">​</a></h1><blockquote><p>&quot;方寸舞台，演尽人生百态。&quot;</p></blockquote><p>北京是中国话剧的发源地和中心，拥有众多历史悠久、风格各异的剧院。从人艺的经典到先锋实验，从传统戏曲到现代话剧，北京的舞台永远充满活力。</p><h2 id="主要剧院" tabindex="-1">主要剧院 <a class="header-anchor" href="#主要剧院" aria-label="Permalink to &quot;主要剧院&quot;">​</a></h2><h3 id="首都剧场-北京人艺" tabindex="-1">首都剧场（北京人艺） <a class="header-anchor" href="#首都剧场-北京人艺" aria-label="Permalink to &quot;首都剧场（北京人艺）&quot;">​</a></h3><p><img src="https://images.unsplash.com/photo-2S_13rwpjKY?w=1200" alt="首都剧场"></p><p>北京人艺是中国最著名的话剧院团，成立于1952年，被誉为&quot;中国话剧的殿堂&quot;。首都剧场是北京人艺的固定演出场所，位于王府井商圈。</p><h4 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h4><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>地址</strong></td><td style="text-align:left;">北京市东城区王府井大街22号</td></tr><tr><td style="text-align:left;"><strong>交通</strong></td><td style="text-align:left;">地铁1号线王府井站A口</td></tr><tr><td style="text-align:left;"><strong>座位数</strong></td><td style="text-align:left;">约900个</td></tr><tr><td style="text-align:left;"><strong>票价</strong></td><td style="text-align:left;">80-680元</td></tr><tr><td style="text-align:left;"><strong>官网</strong></td><td style="text-align:left;"><a href="http://www.bjry.com" target="_blank" rel="noreferrer">www.bjry.com</a></td></tr></tbody></table><h4 id="特色" tabindex="-1">特色 <a class="header-anchor" href="#特色" aria-label="Permalink to &quot;特色&quot;">​</a></h4><ul><li><strong>经典传承</strong>：北京人艺的看家戏《茶馆》《雷雨》等常年上演</li><li><strong>戏骨云集</strong>：濮存昕、冯远征、何冰等著名演员常驻</li><li><strong>京味文化</strong>：以京味话剧著称，台词韵味十足</li></ul><hr><h3 id="国家大剧院戏剧场" tabindex="-1">国家大剧院戏剧场 <a class="header-anchor" href="#国家大剧院戏剧场" aria-label="Permalink to &quot;国家大剧院戏剧场&quot;">​</a></h3><p>国家大剧院戏剧场是中国最高级别的戏剧演出场所之一，设施一流，音效极佳。</p><h4 id="基本信息-1" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息-1" aria-label="Permalink to &quot;基本信息&quot;">​</a></h4><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>地址</strong></td><td style="text-align:left;">北京市西城区西长安街2号</td></tr><tr><td style="text-align:left;"><strong>交通</strong></td><td style="text-align:left;">地铁1号线天安门西站B口</td></tr><tr><td style="text-align:left;"><strong>座位数</strong></td><td style="text-align:left;">1035个</td></tr><tr><td style="text-align:left;"><strong>票价</strong></td><td style="text-align:left;">80-880元</td></tr><tr><td style="text-align:left;"><strong>官网</strong></td><td style="text-align:left;"><a href="http://www.chncpa.org" target="_blank" rel="noreferrer">www.chncpa.org</a></td></tr></tbody></table><h4 id="特色-1" tabindex="-1">特色 <a class="header-anchor" href="#特色-1" aria-label="Permalink to &quot;特色&quot;">​</a></h4><ul><li><strong>国际视野</strong>：经常引进国外优秀剧目</li><li><strong>制作精良</strong>：舞台设计和制作水准一流</li><li><strong>综合艺术</strong>：涵盖话剧、歌剧、舞剧等多种艺术形式</li></ul><hr><h3 id="天桥艺术中心" tabindex="-1">天桥艺术中心 <a class="header-anchor" href="#天桥艺术中心" aria-label="Permalink to &quot;天桥艺术中心&quot;">​</a></h3><p>天桥艺术中心是北京最新、最现代化的艺术演出中心，拥有大、中、小三个剧场，是北京话剧演出的重要场所。</p><h4 id="基本信息-2" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息-2" aria-label="Permalink to &quot;基本信息&quot;">​</a></h4><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>地址</strong></td><td style="text-align:left;">北京市西城区天桥南大街9号</td></tr><tr><td style="text-align:left;"><strong>交通</strong></td><td style="text-align:left;">地铁8号线天桥站A口</td></tr><tr><td style="text-align:left;"><strong>座位数</strong></td><td style="text-align:left;">大剧场1600个，中剧场1000个，小剧场400个</td></tr><tr><td style="text-align:left;"><strong>票价</strong></td><td style="text-align:left;">80-1080元</td></tr><tr><td style="text-align:left;"><strong>官网</strong></td><td style="text-align:left;"><a href="http://www.tqpac.com" target="_blank" rel="noreferrer">www.tqpac.com</a></td></tr></tbody></table><h4 id="特色-2" tabindex="-1">特色 <a class="header-anchor" href="#特色-2" aria-label="Permalink to &quot;特色&quot;">​</a></h4><ul><li><strong>设施一流</strong>：拥有北京最先进的舞台设施</li><li><strong>剧目丰富</strong>：涵盖话剧、音乐剧、舞剧等多种类型</li><li><strong>先锋实验</strong>：经常上演先锋实验剧目</li></ul><hr><h3 id="中国国家话剧院" tabindex="-1">中国国家话剧院 <a class="header-anchor" href="#中国国家话剧院" aria-label="Permalink to &quot;中国国家话剧院&quot;">​</a></h3><p>中国国家话剧院是中国国家级的话剧艺术表演团体，其剧场位于北京东城区。</p><h4 id="基本信息-3" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息-3" aria-label="Permalink to &quot;基本信息&quot;">​</a></h4><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>地址</strong></td><td style="text-align:left;">北京市东城区广安门外大街277号</td></tr><tr><td style="text-align:left;"><strong>交通</strong></td><td style="text-align:left;">地铁7号线达官营站C口</td></tr><tr><td style="text-align:left;"><strong>座位数</strong></td><td style="text-align:left;">约800个</td></tr><tr><td style="text-align:left;"><strong>票价</strong></td><td style="text-align:left;">80-580元</td></tr><tr><td style="text-align:left;"><strong>官网</strong></td><td style="text-align:left;"><a href="http://www.npa.org.cn" target="_blank" rel="noreferrer">www.npa.org.cn</a></td></tr></tbody></table><h4 id="特色-3" tabindex="-1">特色 <a class="header-anchor" href="#特色-3" aria-label="Permalink to &quot;特色&quot;">​</a></h4><ul><li><strong>国家级院团</strong>：代表国家最高水平的话剧表演</li><li><strong>经典剧目</strong>：常年上演国内外经典剧目</li><li><strong>创新实验</strong>：积极探索话剧创新</li></ul><hr><h3 id="保利剧院" tabindex="-1">保利剧院 <a class="header-anchor" href="#保利剧院" aria-label="Permalink to &quot;保利剧院&quot;">​</a></h3><p>保利剧院是北京著名的演出场所，经常上演国内外高水平的话剧、音乐剧。</p><h4 id="基本信息-4" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息-4" aria-label="Permalink to &quot;基本信息&quot;">​</a></h4><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>地址</strong></td><td style="text-align:left;">北京市东城区东直门南大街14号</td></tr><tr><td style="text-align:left;"><strong>交通</strong></td><td style="text-align:left;">地铁2号线东四十条站B口</td></tr><tr><td style="text-align:left;"><strong>座位数</strong></td><td style="text-align:left;">约1400个</td></tr><tr><td style="text-align:left;"><strong>票价</strong></td><td style="text-align:left;">80-1280元</td></tr><tr><td style="text-align:left;"><strong>官网</strong></td><td style="text-align:left;"><a href="http://www.blpolytheatre.com" target="_blank" rel="noreferrer">www.blpolytheatre.com</a></td></tr></tbody></table><h4 id="特色-4" tabindex="-1">特色 <a class="header-anchor" href="#特色-4" aria-label="Permalink to &quot;特色&quot;">​</a></h4><ul><li><strong>国际化</strong>：经常引进国外优秀剧目</li><li><strong>音乐剧为主</strong>：以音乐剧和国际演出为主</li><li><strong>设施一流</strong>：音响和灯光设备一流</li></ul><hr><h3 id="北京喜剧院" tabindex="-1">北京喜剧院 <a class="header-anchor" href="#北京喜剧院" aria-label="Permalink to &quot;北京喜剧院&quot;">​</a></h3><p>北京喜剧院是专门上演喜剧的剧院，是北京喜剧文化的重要阵地。</p><h4 id="基本信息-5" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息-5" aria-label="Permalink to &quot;基本信息&quot;">​</a></h4><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>地址</strong></td><td style="text-align:left;">北京市东城区朝阳门北大街11号</td></tr><tr><td style="text-align:left;"><strong>交通</strong></td><td style="text-align:left;">地铁2号线朝阳门站A口</td></tr><tr><td style="text-align:left;"><strong>座位数</strong></td><td style="text-align:left;">约500个</td></tr><tr><td style="text-align:left;"><strong>票价</strong></td><td style="text-align:left;">80-380元</td></tr></tbody></table><h4 id="特色-5" tabindex="-1">特色 <a class="header-anchor" href="#特色-5" aria-label="Permalink to &quot;特色&quot;">​</a></h4><ul><li><strong>喜剧为主</strong>：专门上演喜剧作品</li><li><strong>轻松愉快</strong>：氛围轻松，适合休闲观剧</li><li><strong>票价亲民</strong>：票价相对较低</li></ul><hr><h2 id="推荐话剧剧目" tabindex="-1">推荐话剧剧目 <a class="header-anchor" href="#推荐话剧剧目" aria-label="Permalink to &quot;推荐话剧剧目&quot;">​</a></h2><h3 id="经典必看" tabindex="-1">经典必看 <a class="header-anchor" href="#经典必看" aria-label="Permalink to &quot;经典必看&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">剧目</th><th style="text-align:left;">作者</th><th style="text-align:left;">类型</th><th style="text-align:left;">简介</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>《茶馆》</strong></td><td style="text-align:left;">老舍</td><td style="text-align:left;">经典</td><td style="text-align:left;">老北京茶馆的兴衰，展现社会变迁</td></tr><tr><td style="text-align:left;"><strong>《雷雨》</strong></td><td style="text-align:left;">曹禺</td><td style="text-align:left;">经典</td><td style="text-align:left;">家庭悲剧，中国现代话剧奠基之作</td></tr><tr><td style="text-align:left;"><strong>《日出》</strong></td><td style="text-align:left;">曹禺</td><td style="text-align:left;">经典</td><td style="text-align:left;">都市生活的悲欢离合</td></tr><tr><td style="text-align:left;"><strong>《原野》</strong></td><td style="text-align:left;">曹禺</td><td style="text-align:left;">经典</td><td style="text-align:left;">复仇与救赎的故事</td></tr><tr><td style="text-align:left;"><strong>《骆驼祥子》</strong></td><td style="text-align:left;">老舍</td><td style="text-align:left;">经典</td><td style="text-align:left;">人力车夫的悲惨命运</td></tr><tr><td style="text-align:left;"><strong>《四世同堂》</strong></td><td style="text-align:left;">老舍</td><td style="text-align:left;">经典</td><td style="text-align:left;">抗战时期北京市民生活</td></tr><tr><td style="text-align:left;"><strong>《天下第一楼》</strong></td><td style="text-align:left;">何冀平</td><td style="text-align:left;">经典</td><td style="text-align:left;">烤鸭店的兴衰</td></tr><tr><td style="text-align:left;"><strong>《李白》</strong></td><td style="text-align:left;">郭启宏</td><td style="text-align:left;">经典</td><td style="text-align:left;">诗仙李白的传奇人生</td></tr></tbody></table><h3 id="当代佳作" tabindex="-1">当代佳作 <a class="header-anchor" href="#当代佳作" aria-label="Permalink to &quot;当代佳作&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">剧目</th><th style="text-align:left;">作者/导演</th><th style="text-align:left;">类型</th><th style="text-align:left;">简介</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>《暗恋桃花源》</strong></td><td style="text-align:left;">赖声川</td><td style="text-align:left;">爱情</td><td style="text-align:left;">古今交错的爱情故事</td></tr><tr><td style="text-align:left;"><strong>《恋爱的犀牛》</strong></td><td style="text-align:left;">孟京辉</td><td style="text-align:left;">先锋</td><td style="text-align:left;">偏执的爱情寓言</td></tr><tr><td style="text-align:left;"><strong>《活着》</strong></td><td style="text-align:left;">孟京辉</td><td style="text-align:left;">先锋</td><td style="text-align:left;">根据余华小说改编</td></tr><tr><td style="text-align:left;"><strong>《两只狗的生活意见》</strong></td><td style="text-align:left;">孟京辉</td><td style="text-align:left;">喜剧</td><td style="text-align:left;">荒诞喜剧</td></tr><tr><td style="text-align:left;"><strong>《窝头会馆》</strong></td><td style="text-align:left;">刘恒</td><td style="text-align:left;">京味</td><td style="text-align:left;">老北京四合院的故事</td></tr><tr><td style="text-align:left;"><strong>《北京法源寺》</strong></td><td style="text-align:left;">田沁鑫</td><td style="text-align:left;">历史</td><td style="text-align:left;">戊戌变法的历史再现</td></tr><tr><td style="text-align:left;"><strong>《简·爱》</strong></td><td style="text-align:left;">国家大剧院</td><td style="text-align:left;">话剧</td><td style="text-align:left;">经典名著改编</td></tr><tr><td style="text-align:left;"><strong>《哈姆雷特》</strong></td><td style="text-align:left;">莎士比亚</td><td style="text-align:left;">经典</td><td style="text-align:left;">莎翁经典悲剧</td></tr></tbody></table><h3 id="适合游客" tabindex="-1">适合游客 <a class="header-anchor" href="#适合游客" aria-label="Permalink to &quot;适合游客&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">剧目</th><th style="text-align:left;">推荐理由</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>《茶馆》</strong></td><td style="text-align:left;">最具北京特色的经典话剧，必看</td></tr><tr><td style="text-align:left;"><strong>《雷雨》</strong></td><td style="text-align:left;">中国现代话剧奠基之作</td></tr><tr><td style="text-align:left;"><strong>《四世同堂》</strong></td><td style="text-align:left;">了解老北京生活的窗口</td></tr><tr><td style="text-align:left;"><strong>《窝头会馆》</strong></td><td style="text-align:left;">京味十足，幽默风趣</td></tr><tr><td style="text-align:left;"><strong>《暗恋桃花源》</strong></td><td style="text-align:left;">两岸三地经典，感人至深</td></tr></tbody></table><hr><h2 id="观剧攻略" tabindex="-1">观剧攻略 <a class="header-anchor" href="#观剧攻略" aria-label="Permalink to &quot;观剧攻略&quot;">​</a></h2><h3 id="购票渠道" tabindex="-1">购票渠道 <a class="header-anchor" href="#购票渠道" aria-label="Permalink to &quot;购票渠道&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">渠道</th><th style="text-align:left;">优势</th><th style="text-align:left;">网址</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>大麦网</strong></td><td style="text-align:left;">剧目最全</td><td style="text-align:left;"><a href="http://www.damai.cn" target="_blank" rel="noreferrer">www.damai.cn</a></td></tr><tr><td style="text-align:left;"><strong>猫眼演出</strong></td><td style="text-align:left;">经常有折扣</td><td style="text-align:left;"><a href="http://www.maoyan.com" target="_blank" rel="noreferrer">www.maoyan.com</a></td></tr><tr><td style="text-align:left;"><strong>剧院官网</strong></td><td style="text-align:left;">会员优先</td><td style="text-align:left;">各剧院官网</td></tr><tr><td style="text-align:left;"><strong>微信小程序</strong></td><td style="text-align:left;">方便快捷</td><td style="text-align:left;">各剧院小程序</td></tr></tbody></table><h3 id="选座建议" tabindex="-1">选座建议 <a class="header-anchor" href="#选座建议" aria-label="Permalink to &quot;选座建议&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">位置</th><th style="text-align:left;">体验</th><th style="text-align:left;">价格</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>前排中央</strong></td><td style="text-align:left;">最佳观演位置，演员表情清晰可见</td><td style="text-align:left;">最贵</td></tr><tr><td style="text-align:left;"><strong>中排中央</strong></td><td style="text-align:left;">视野开阔，性价比高</td><td style="text-align:left;">中等</td></tr><tr><td style="text-align:left;"><strong>后排中央</strong></td><td style="text-align:left;">视野较好，价格实惠</td><td style="text-align:left;">较低</td></tr><tr><td style="text-align:left;"><strong>侧边座位</strong></td><td style="text-align:left;">可能有遮挡，但价格便宜</td><td style="text-align:left;">最便宜</td></tr></tbody></table><h3 id="观剧礼仪" tabindex="-1">观剧礼仪 <a class="header-anchor" href="#观剧礼仪" aria-label="Permalink to &quot;观剧礼仪&quot;">​</a></h3><ol><li><strong>提前到场</strong>：建议提前30分钟到场，以免错过开场</li><li><strong>关闭手机</strong>：演出期间请将手机调至静音或关机</li><li><strong>禁止拍照</strong>：演出期间禁止拍照和录像</li><li><strong>保持安静</strong>：演出期间请保持安静，不要大声说话</li><li><strong>鼓掌时机</strong>：演出结束后可以鼓掌，谢幕时可以起身鼓掌</li></ol><h3 id="交通建议" tabindex="-1">交通建议 <a class="header-anchor" href="#交通建议" aria-label="Permalink to &quot;交通建议&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">剧院</th><th style="text-align:left;">交通</th><th style="text-align:left;">周边</th></tr></thead><tbody><tr><td style="text-align:left;">首都剧场</td><td style="text-align:left;">1号线王府井站</td><td style="text-align:left;">王府井商圈</td></tr><tr><td style="text-align:left;">国家大剧院</td><td style="text-align:left;">1号线天安门西站</td><td style="text-align:left;">天安门广场</td></tr><tr><td style="text-align:left;">天桥艺术中心</td><td style="text-align:left;">8号线天桥站</td><td style="text-align:left;">天坛</td></tr><tr><td style="text-align:left;">保利剧院</td><td style="text-align:left;">2号线东四十条站</td><td style="text-align:left;">三里屯</td></tr></tbody></table><hr><h2 id="周边推荐" tabindex="-1">周边推荐 <a class="header-anchor" href="#周边推荐" aria-label="Permalink to &quot;周边推荐&quot;">​</a></h2><h3 id="观剧前后活动" tabindex="-1">观剧前后活动 <a class="header-anchor" href="#观剧前后活动" aria-label="Permalink to &quot;观剧前后活动&quot;">​</a></h3><p><strong>下午观剧前</strong>：</p><ul><li>王府井逛街（首都剧场）</li><li>天坛散步（天桥艺术中心）</li><li>三里屯购物（保利剧院）</li></ul><p><strong>晚间观剧后</strong>：</p><ul><li>王府井夜市（首都剧场）</li><li>前门大街夜游（国家大剧院）</li><li>后海酒吧（天桥艺术中心）</li></ul><hr><p><strong>💡 Tips</strong>：北京的话剧市场非常活跃，建议提前关注各大剧院的演出排期，选择感兴趣的剧目提前购票。经典剧目如《茶馆》《雷雨》等经常一票难求，建议提前预订。</p>',73)])])}const y=e(n,[["render",d]]);export{x as __pageData,y as default};
